import{_ as a,c as i,o as e,ag as n}from"./chunks/framework.GdcW6lnn.js";const k=JSON.parse('{"title":"Основы Vue.js: Vue CLI","description":"","frontmatter":{},"headers":[],"relativePath":"basics_vue/vue-cli.md","filePath":"basics_vue/vue-cli.md"}'),l={name:"basics_vue/vue-cli.md"};function t(p,s,h,o,d,c){return e(),i("div",null,s[0]||(s[0]=[n(`<h1 id="основы-vue-js-vue-cli" tabindex="-1">Основы Vue.js: Vue CLI <a class="header-anchor" href="#основы-vue-js-vue-cli" aria-label="Permalink to “Основы Vue.js: Vue CLI”">​</a></h1><p><strong>Vue CLI</strong> — это стандартный инструментарий для разработки на Vue.js. Он предоставляет:</p><ul><li><strong>Быструю настройку проекта:</strong> Генерация каркаса нового проекта с базовой конфигурацией.</li><li><strong>Готовую систему сборки:</strong> Преднастроенный Webpack с разумными дефолтными настройками.</li><li><strong>Возможность расширения:</strong> Система плагинов для добавления дополнительных функций (Babel, TypeScript, ESLint, Vue Router, Vuex и др.).</li><li><strong>Графический интерфейс (Vue UI):</strong> Визуальный инструмент для управления проектами.</li><li><strong>Мгновенную прототипизацию:</strong> Возможность быстро создавать прототипы однофайловых компонентов (<code>.vue</code>) без полной настройки проекта.</li></ul><h2 id="установка-vue-cli" tabindex="-1">Установка Vue CLI <a class="header-anchor" href="#установка-vue-cli" aria-label="Permalink to “Установка Vue CLI”">​</a></h2><p>Для использования Vue CLI необходимо установить его глобально с помощью npm или yarn:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vue/cli</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># или</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vue/cli</span></span></code></pre></div><p>После установки вы сможете использовать команду <code>vue</code> в вашей командной строке. Чтобы проверить установленную версию, выполните:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vue</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><h2 id="создание-нового-проекта" tabindex="-1">Создание нового проекта <a class="header-anchor" href="#создание-нового-проекта" aria-label="Permalink to “Создание нового проекта”">​</a></h2><p>Для создания нового проекта Vue.js используйте команду <code>vue create &lt;project-name&gt;</code>, где <code>&lt;project-name&gt;</code> — это имя вашего проекта.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-vue-app</span></span></code></pre></div><p>При выполнении этой команды Vue CLI предложит вам выбрать предустановленный шаблон (preset) или вручную выбрать необходимые функции.</p><h3 id="предустановленные-шаблоны-presets" tabindex="-1">Предустановленные шаблоны (Presets) <a class="header-anchor" href="#предустановленные-шаблоны-presets" aria-label="Permalink to “Предустановленные шаблоны (Presets)”">​</a></h3><p>Vue CLI поставляется с несколькими предустановленными шаблонами, которые включают в себя стандартный набор инструментов для разработки:</p><ul><li><strong><code>default (babel, eslint)</code>:</strong> Базовая настройка с Babel (для поддержки современного JavaScript в старых браузерах) и ESLint (для линтинга кода).</li><li><strong><code>default (babel, eslint) - In history mode?</code>:</strong> То же, что и <code>default</code>, но с запросом, следует ли использовать режим истории браузера для Vue Router (требует настройки сервера для SPA).</li></ul><h3 id="ручная-настроика-manually-select-features" tabindex="-1">Ручная настройка (Manually select features) <a class="header-anchor" href="#ручная-настроика-manually-select-features" aria-label="Permalink to “Ручная настройка (Manually select features)”">​</a></h3><p>Если вы выберете &quot;Manually select features&quot;, Vue CLI предложит вам список функций, которые вы можете добавить в свой проект:</p><ul><li><strong>Babel:</strong> Транспиляция JavaScript.</li><li><strong>TypeScript:</strong> Поддержка строго типизированного JavaScript.</li><li><strong>Progressive Web App (PWA) Support:</strong> Добавление возможностей PWA.</li><li><strong>Vue Router:</strong> Официальная библиотека маршрутизации для Vue.js.</li><li><strong>Vuex:</strong> Официальная библиотека управления состоянием для Vue.js.</li><li><strong>CSS Pre-processors:</strong> Поддержка CSS-препроцессоров (Sass/SCSS, Less, Stylus).</li><li><strong>Linter / Formatter:</strong> Инструменты для линтинга и форматирования кода (ESLint, Prettier).</li><li><strong>Unit Testing:</strong> Поддержка модульного тестирования (Jest, Mocha).</li><li><strong>E2E Testing:</strong> Поддержка сквозного тестирования (Cypress, Nightwatch).</li></ul><p>После выбора необходимых функций Vue CLI установит все зависимости и сгенерирует базовую структуру вашего проекта.</p><h2 id="структура-проекта-vue-cli-по-умолчанию" tabindex="-1">Структура проекта Vue CLI (по умолчанию) <a class="header-anchor" href="#структура-проекта-vue-cli-по-умолчанию" aria-label="Permalink to “Структура проекта Vue CLI (по умолчанию)”">​</a></h2><p>После успешного создания проекта вы увидите следующую структуру каталогов (может немного отличаться в зависимости от выбранных функций):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my-vue-app/</span></span>
<span class="line"><span>├── public/</span></span>
<span class="line"><span>│   └── index.html</span></span>
<span class="line"><span>│   └── favicon.ico</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── assets/</span></span>
<span class="line"><span>│   │   └── logo.png</span></span>
<span class="line"><span>│   ├── components/</span></span>
<span class="line"><span>│   │   └── HelloWorld.vue</span></span>
<span class="line"><span>│   ├── App.vue</span></span>
<span class="line"><span>│   └── main.js</span></span>
<span class="line"><span>├── .gitignore</span></span>
<span class="line"><span>├── babel.config.js</span></span>
<span class="line"><span>├── package.json</span></span>
<span class="line"><span>├── README.md</span></span>
<span class="line"><span>└── yarn.lock (или package-lock.json)</span></span></code></pre></div><ul><li><strong><code>public/</code>:</strong> Содержит статические ресурсы, которые копируются непосредственно в финальную сборку (например, <code>index.html</code>, <code>favicon.ico</code>).</li><li><strong><code>src/</code>:</strong> Основная директория с исходным кодом вашего приложения. <ul><li><strong><code>assets/</code>:</strong> Ресурсы, которые обрабатываются Webpack (например, изображения).</li><li><strong><code>components/</code>:</strong> Каталог для ваших многократно используемых Vue-компонентов.</li><li><strong><code>App.vue</code>:</strong> Корневой компонент вашего приложения.</li><li><strong><code>main.js</code>:</strong> Точка входа приложения, где создается экземпляр Vue и подключаются плагины.</li></ul></li><li><strong><code>.gitignore</code>:</strong> Файл, указывающий файлы и директории, которые Git должен игнорировать.</li><li><strong><code>babel.config.js</code>:</strong> Конфигурация Babel.</li><li><strong><code>package.json</code>:</strong> Файл с информацией о проекте и его зависимостях (npm или yarn).</li><li><strong><code>README.md</code>:</strong> Файл с описанием проекта.</li><li><strong><code>yarn.lock</code> / <code>package-lock.json</code>:</strong> Файлы блокировки версий зависимостей.</li></ul><p>Если вы добавили Vue Router или Vuex, вы также увидите директории <code>router/</code> и <code>store/</code> внутри <code>src/</code>.</p><h2 id="основные-команды-vue-cli" tabindex="-1">Основные команды Vue CLI <a class="header-anchor" href="#основные-команды-vue-cli" aria-label="Permalink to “Основные команды Vue CLI”">​</a></h2><p>Vue CLI предоставляет ряд полезных команд для разработки:</p><ul><li><p><strong><code>vue serve</code>:</strong> Запускает локальный сервер разработки с горячей перезагрузкой (hot-reloading). Это означает, что при изменении файлов в <code>src/</code> браузер автоматически обновится без полной перезагрузки страницы.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-vue-app</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span></code></pre></div><p>Обычно приложение будет доступно по адресу <code>http://localhost:8080/</code>.</p></li><li><p><strong><code>vue build</code>:</strong> Собирает ваше приложение для production. Результат сборки помещается в директорию <code>dist/</code>.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>Вы можете использовать различные флаги для настройки сборки (например, <code>--mode production</code>, <code>--dest my-output-dir</code>).</p></li><li><p><strong><code>vue inspect</code>:</strong> Позволяет просмотреть финальную конфигурацию Webpack вашего проекта. Это полезно для понимания того, как Vue CLI настроил сборку, и для отладки проблем.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> inspect</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> inspect</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --plugins</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Показать список плагинов Webpack</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> inspect</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vue</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Показать конфигурацию для обработки .vue файлов</span></span></code></pre></div></li><li><p><strong><code>vue add &lt;plugin&gt;</code>:</strong> Устанавливает и добавляет плагин Vue CLI в ваш проект. Плагины могут предоставлять новые функции, добавлять зависимости и изменять конфигурацию проекта.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> router</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Добавить Vue Router</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vuex</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Добавить Vuex</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vue/cli-plugin-eslint</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Добавить плагин ESLint</span></span></code></pre></div></li><li><p><strong><code>vue invoke &lt;plugin&gt; [options]</code>:</strong> Вызывает установленный плагин для выполнения определенных действий или настройки.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> invoke</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eslint</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> airbnb</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Настроить ESLint с конфигурацией Airbnb</span></span></code></pre></div></li><li><p><strong><code>vue ui</code>:</strong> Запускает графический интерфейс Vue CLI в вашем браузере. Vue UI предоставляет визуальный способ управления вашими проектами, установки плагинов, выполнения задач (serve, build, inspect) и многого другого.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ui</span></span></code></pre></div><p>Обычно Vue UI будет доступен по адресу <code>http://localhost:8000/</code>.</p></li></ul><h2 id="использование-vue-ui" tabindex="-1">Использование Vue UI <a class="header-anchor" href="#использование-vue-ui" aria-label="Permalink to “Использование Vue UI”">​</a></h2><p>Vue UI предоставляет интуитивно понятный интерфейс для выполнения большинства задач Vue CLI без использования командной строки. Вы можете:</p><ul><li>Создавать и импортировать проекты.</li><li>Управлять зависимостями (устанавливать, обновлять, удалять).</li><li>Устанавливать и настраивать плагины.</li><li>Выполнять задачи сборки, запуска сервера и инспектирования Webpack.</li><li>Просматривать логи и управлять конфигурацией.</li></ul><h2 id="расширение-возможностеи-с-помощью-плагинов" tabindex="-1">Расширение возможностей с помощью плагинов <a class="header-anchor" href="#расширение-возможностеи-с-помощью-плагинов" aria-label="Permalink to “Расширение возможностей с помощью плагинов”">​</a></h2><p>Система плагинов Vue CLI позволяет легко расширять функциональность вашего проекта. Существует множество официальных и сторонних плагинов, которые могут добавить поддержку TypeScript, PWA, различных CSS-препроцессоров, инструментов тестирования и многого другого.</p><p>При установке плагина Vue CLI обычно автоматически обновляет файлы вашего проекта (например, добавляет зависимости в <code>package.json</code>, изменяет конфигурацию Webpack) и может задавать вам вопросы для настройки.</p><h2 id="мгновенная-прототипизация" tabindex="-1">Мгновенная прототипизация <a class="header-anchor" href="#мгновенная-прототипизация" aria-label="Permalink to “Мгновенная прототипизация”">​</a></h2><p>Vue CLI также предоставляет возможность быстро создавать прототипы однофайловых компонентов (<code>.vue</code>) без необходимости создавать полноценный проект. Для этого установите глобальный сервис прототипирования:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vue/cli-service-global</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># или</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vue/cli-service-global</span></span></code></pre></div><p>Затем вы можете перейти в директорию, содержащую ваш <code>.vue</code> файл, и запустить прототип с помощью команды <code>vue serve &lt;YourComponent.vue&gt;</code>.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> MyComponent.vue</span></span></code></pre></div><p>Это запустит локальный сервер и отобразит ваш компонент.</p><h2 id="заключение" tabindex="-1">Заключение <a class="header-anchor" href="#заключение" aria-label="Permalink to “Заключение”">​</a></h2><p>Vue CLI является незаменимым инструментом для разработки приложений на Vue.js. Он значительно ускоряет процесс создания проектов, предоставляет готовую систему сборки и позволяет легко добавлять необходимые функции с помощью плагинов. Использование Vue CLI помогает сосредоточиться на написании кода вашего приложения, а не на настройке окружения. Графический интерфейс Vue UI делает управление проектами еще более удобным, особенно для новичков.</p>`,41)]))}const g=a(l,[["render",t]]);export{k as __pageData,g as default};
